ruleset.script:
var lsContext = new LiveSiteDataCapture();
var SCRIPT_LOCATION   = "/iw-bin/sync_metadata.ipl";

function pad(n) {
    return (n < 10) ? ("0" + n) : n;
}

function init() {
    // set the publish date to today if not set
    if ( IWDatacapture.getItem("/press_release/publish_date").getValue() == "")
    {
        var today = new Date();
        IWDatacapture.getItem("/press_release/publish_date").setValue(today.getFullYear() + "-" + pad(today.getMonth() + 1) + "-" + pad(today.getDate()));
    }

   if ( IWDatacapture.getItem("/press_release/subcategory").getValue() == "")
    {

        IWDatacapture.getItem("/press_release/subcategory").setValue("Insights");
    }


populateParentPages();


  FilenameSuggestion.setFilenameGenerator(getFilename);


  //      IWEventRegistry.addItemHandler( "/press_release/myButton", "onCallout", handleOnCallout );


    // ========== ADD THIS SECTION ==========
    // BREADCRUMB DISPLAY ON LOAD - Show existing sitemap values
    try {
        // Only proceed if breadcrumb_display_text is blank
        var existing_breadcrumb = "";
        try {
            existing_breadcrumb = IWDatacapture.getItem("/press_release/breadcrumb_display_text").getValue() || "";
        } catch(e) {}

        if (existing_breadcrumb == "") {
            var parent_page = "";

            // Get parent_page (Sitemap SELECT - hidden but may have saved values)
            try {
                var parent_item = IWDatacapture.getItem("/press_release/parent_page");
                if (parent_item != null) {
                    var selectedIdx = parent_item.getValue();
                    var parentOptions = parent_item.getOptions();
                    if (parentOptions != null && selectedIdx != null && selectedIdx !== "" && parentOptions[selectedIdx] != null) {
                        parent_page = parentOptions[selectedIdx].value || "";
                    }
                }
            } catch(e) {}

            // Helper function to extract text from HTML li/a tags
            function extractLabelsFromHtml(html) {
                var labels = [];
                var regex = />([^<]+)<\/a>/g;
                var match;
                while ((match = regex.exec(html)) !== null) {
                    if (match[1].trim() != "") {
                        labels.push(match[1].trim());
                    }
                }
                return labels.join(" | ");
            }

            // If sitemap has values, display them on load
            if (parent_page != "") {
                var breadcrumb_value = extractLabelsFromHtml(parent_page);
                if (breadcrumb_value == "") {
                    breadcrumb_value = "Home | Insights"; // fallback
                }
                console.log("Sitemap breadcrumb on load: [" + breadcrumb_value + "]");
                try {
                    IWDatacapture.getItem("/press_release/breadcrumb_display_text").setValue(breadcrumb_value);
                } catch(e) {}
            }
        } else {
            console.log("Breadcrumb display text already has value: [" + existing_breadcrumb + "]");
        }
    } catch(e) {
        console.log("Breadcrumb load error: " + e.message);
    }
    // ========== END OF ADDED SECTION ==========


}

function handleOnSaveDone() {

  var service_url  = https:// + window.location.hostname + SCRIPT_LOCATION ;
  var params                          = new Object();
  params.dcr                        = IWDatacapture.getDCRPath();
  IWDatacapture.callServer( service_url, params );
  return true;
}

function handleOnSave ()
  {
   // replace $ signs in title and description
      var title = IWDatacapture.getItem("/press_release/title").getValue();
      title = title.replace(/\$/g, '&#36;');
      /*title = title.replace(/\"/g, '&quot;');
      title = title.replace(/\./g, '&period;');*/
      IWDatacapture.getItem("/press_release/title").setValue(title);

      var description = IWDatacapture.getItem("/press_release/description").getValue();
      description = description.replace(/\$/g, '&#36;');
      //description = description.replace(/\"/g, '&quot;');
      IWDatacapture.getItem("/press_release/description").setValue(description);



    // AUTHOR DISPLAY TEXT SECTION

    var author_display_text = "";

    if (IWDatacapture.getItem("/press_release/byline/author_name_byline").getValue() != "") {
      console.log(IWDatacapture.getItem("/press_release/byline/author_name_byline").getValue());
      author_display_text = IWDatacapture.getItem("/press_release/byline/author_name_byline").getValue();
    }
    else {

      var authors = [];

      for (let i = 1; i <= 11; i++) {
      // Make sure this loops end value is the same as max number of authors in the root container
        var author_item = IWDatacapture.getItem("/press_release/author-section[" + i.toString() + "]/author/author_name_new");
        var author_company = IWDatacapture.getItem("/press_release/author-section[" + i.toString() + "]/author/author_company_new");
        if (author_item != null && author_item.getValue() != "") {
          var author_str = "";
          if (author_company != null && author_company.getValue() != "" && IWDatacapture.getItem("/press_release/author-section[" + i.toString() + "]/author/title_append_new").getValue() == "0") {
            author_str += ", " + author_company.getValue();
          }

          authors.push(author_item.getValue() + author_str);
        }
      }


      if (authors.length == 1) {
        author_display_text += "<strong>" + authors[0] + "</strong>";
      }
      else if (authors.length == 2) {
        author_display_text += "<strong>" + authors[0] + "</strong>";
        author_display_text += " and <strong>" + authors[1] + "</strong>";
      }
      else if (authors.length > 2) {
        author_display_text += "<strong>" + authors[0] + "</strong>";
        for (var i = 1; i < authors.length - 1; i++) {
          if (author_display_text.charAt(author_display_text.length - 1) != ",") {
            author_display_text += ","
          }
          author_display_text += " " + "<strong>" + authors[i] + "</strong>";
        }
        author_display_text += " & " + "<strong>" + authors[authors.length - 1] + "</strong>";
      }
    }

    if (author_display_text.charAt(author_display_text.length - 1) == ",") {
      author_display_text = author_display_text.slice(0, -1)
    }

    console.log(author_display_text)

    IWDatacapture.getItem("/press_release/author_display_text").setValue(author_display_text);

    console.log(IWDatacapture.getItem("/press_release/author_display_text").getValue());

    console.log(IWDatacapture.getItem("/press_release/byline/author_title_byline").getValue());



       // BREADCRUMB VALUE SECTION
    try {
        var breadcrumb_value = "";
        var manual_breadcrumb = "";
        var dropdown_breadcrumb = "";
        var parent_page = "";

        // Get manual-breadcrumb (text field)
        try { manual_breadcrumb = IWDatacapture.getItem("/press_release/manual-breadcrumb").getValue() || ""; } catch(e) {}

        // Get dropdown-breadcrumb (SELECT)
        try {
            var dropdown_item = IWDatacapture.getItem("/press_release/dropdown-breadcrumb");
            if (dropdown_item != null) {
                var selectedIndex = dropdown_item.getValue();
                var options = dropdown_item.getOptions();
                if (options != null && selectedIndex != null && selectedIndex !== "" && options[selectedIndex] != null) {
                    dropdown_breadcrumb = options[selectedIndex].value || "";
                }
            }
        } catch(e) {}

        // Get parent_page (SELECT)
        try {
            var parent_item = IWDatacapture.getItem("/press_release/parent_page");
            if (parent_item != null) {
                var selectedIdx = parent_item.getValue();
                var parentOptions = parent_item.getOptions();
                if (parentOptions != null && selectedIdx != null && selectedIdx !== "" && parentOptions[selectedIdx] != null) {
                    parent_page = parentOptions[selectedIdx].value || "";
                }
            }
        } catch(e) {}

        // Helper function to extract text from HTML li/a tags
        function extractLabelsFromHtml(html) {
            var labels = [];
            // Match text between > and </a>
            var regex = />([^<]+)<\/a>/g;
            var match;
            while ((match = regex.exec(html)) !== null) {
                if (match[1].trim() != "") {
                    labels.push(match[1].trim());
                }
            }
            return labels.join(" | ");
        }

        if (manual_breadcrumb != "") {
            // Extract labels from HTML
            breadcrumb_value = extractLabelsFromHtml(manual_breadcrumb);
            if (breadcrumb_value == "") {
                breadcrumb_value = manual_breadcrumb; // fallback if not HTML
            }
        }
        else if (dropdown_breadcrumb != "") {
            // Format: /en/insights::Insights|/en/insights/ai::AI
            var parts = dropdown_breadcrumb.split("|");
            var labels = ["Home"];
            for (var i = 0; i < parts.length; i++) {
                var linkLabel = parts[i].split("::");
                if (linkLabel.length == 2) {
                    labels.push(linkLabel[1]);
                }
            }
            breadcrumb_value = labels.join(" | ");
        }
        else if (parent_page != "") {
            // Extract labels from HTML
            breadcrumb_value = extractLabelsFromHtml(parent_page);
            if (breadcrumb_value == "") {
                breadcrumb_value = "Home | Insights"; // fallback
            }
        }
        else {
            breadcrumb_value = "Home | Insights";
        }

        console.log("breadcrumb_value: [" + breadcrumb_value + "]");

        try { IWDatacapture.getItem("/press_release/breadcrumb_display_text").setValue(breadcrumb_value); } catch(e) {}
    } catch(e) {
        console.log("Breadcrumb error: " + e.message);
    }




    // AUTHOR DISPLAY TEXT SECTION

    var time_to_read = IWDatacapture.getItem("/press_release/time_to_read").getValue();

    var typeOptions = IWDatacapture.getItem("/press_release/story_type").getOptions();
    var typeSelected = IWDatacapture.getItem("/press_release/story_type").getValue();
    var type = typeOptions[typeSelected].value;

  if ((time_to_read == '')&&(type=='text')&&(IWDatacapture.getItem("/press_release/content") != null))
  {

  var content = IWDatacapture.getItem("/press_release/content").getChildren()[0].getValue();
  var time = Math.round($(content).text().split(" ").length / 250);
   IWDatacapture.getItem("/press_release/time_to_read").setValue(time + " min");
  }
       var can_url = IWDatacapture.getItem("/press_release/can_url").getValue();

                   if (can_url == '') {
         var canonical_url = IWDatacapture.getDCRPath();
         can_url = canonical_url.replace("//strplvact10001.fg.rbc.com/default/main/internet/rbccm/WORKAREA/shared/",https://www.rbccm.com/en/story/story.page?dcr=);
       }
      IWDatacapture.getItem("/press_release/can_url").setValue(can_url);
      return true;
  }


/**
* Gets the suggested filename.
*/
function getFilename()
{

    var date = IWDatacapture.getItem("/press_release/publish_date").getValue();
    var dateArr = date.split("-");

    var fileName = IWDatacapture.getItem("/press_release/title").getValue();
      fileName = fileName.replace(/\$/g, '');
      fileName = fileName.replace(/\"/g, '');
      fileName = fileName.replace(/\./g, '');

   if (IWDatacapture.getItem("/press_release/related_article_side").getValue() == "1") {
     return "/related-articles/" +                  lsContext.getSafeFilename(fileName.toLowerCase()).replace(/\_/g, '-');
  }
  else if (IWDatacapture.getItem("/press_release/related_article_side").getValue() == "0") {
    return dateArr[0] + "/" + dateArr[1] + "/" +                        lsContext.getSafeFilename(fileName.toLowerCase()).replace(/\_/g, '-');
  }
}




function populateParentPages (){
    var pathToXml = "/iw-mount/default/main/internet/rbccm/WORKAREA/shared/sites/rbccm/default.sitemap";
  $.ajax({
    type: "GET",
    url: pathToXml,
    dataType: "xml",
    success: function(xml){
    console.log(xml);


        var rootNode = $(xml).find("segment").children("node");
        console.log(rootNode.children("label").text());
      console.log(rootNode.children("link").text());


      IWDatacapture.getItem("/press_release/parent_page").addOption(new Option("Home", '<li><a href="/en/">Home</a></li>', false, false));


      rootNode.children("node").each(function (){
        var self = $(this);

        if ($(this).attr('visible-in-breadcrumbs') !== 'true') {
            return;
        }

        var label = $(this).children("label").text();
        var link = $(this).children("link").children("value").text();
        console.log(label + " | " + link);

        var linkHref = link.startsWith('http') ? link : '/en/' + link;

        IWDatacapture.getItem("/press_release/parent_page").addOption(new Option(label, '<li><a href="/en/">Home</a></li><li><a href="'+linkHref+'">' + label +'</a></li>', false, false));

      });




      rootNode.children("node").each(function (){
        var self = $(this);

        if ($(this).attr('visible-in-breadcrumbs') !== 'true') {
            return;
        }

        var label = $(this).children("label").text();
        var link = $(this).children("link").children("value").text();


        if (label != "Policies and Disclaimers"){
        self.children("node").each(function (){

          if ($(this).attr('visible-in-breadcrumbs') !== 'true') {
            return;
        }

        var clabel = $(this).children("label").text();
        var clink = $(this).children("link").children("value").text();
        console.log(label + " > " + clabel + " | " + clink);

        var parentLinkHref = link.startsWith('http') ? link : '/en/' + link;
        var childLinkHref = clink.startsWith('http') ? clink : '/en/' + clink;

        IWDatacapture.getItem("/press_release/parent_page").addOption(new Option("  " + clabel, '<li><a href="/en/">Home</a></li><li><a href="'+parentLinkHref+'">' + label +'</a></li><li><a href="'+childLinkHref+'">' + clabel +'</a></li>', false, false));
        });
        }


      });



      }
   });
}

function populateAuthor(item)
{
   console.log(item.getValue());

   var pathToXml = "/iw-mount/default/main/internet/rbccm/WORKAREA/shared" + item.getValue();
   $.ajax({
    type: "GET",
    url: pathToXml,
    dataType: "xml",
    success: function(xml){
    console.log(xml);
    IWDatacapture.getItem("/press_release/author_name").setValue($(xml).find("name").text());
    IWDatacapture.getItem("/press_release/author_id").setValue($(xml).find("id").text());
    IWDatacapture.getItem("/press_release/author_title").setValue($(xml).find("title").text() + ", " +  $(xml).find("subtitle").text());
    IWDatacapture.getItem("/press_release/author_image").setValue($(xml).find("photo").text());
    IWDatacapture.getItem("/press_release/author_email").setValue($(xml).find("email").text());
    IWDatacapture.getItem("/press_release/author_linkedin").setValue($(xml).find("linkedin").text());
    IWDatacapture.getItem("/press_release/author_twitter").setValue($(xml).find("twitter").text());
    IWDatacapture.getItem("/press_release/author_bio").setValue($(xml).find("bio").text());
      }
   });
}

function populateAuthorNew(item)
{
   console.log(item);
   console.log(item.getName());
   console.log(item.getValue());

   var itemPath = item.getName().replace("author_dcr_new", "");
   console.log(itemPath)

   var pathToXml = "/iw-mount/default/main/internet/rbccm/WORKAREA/shared" + item.getValue();
   $.ajax({
    type: "GET",
    url: pathToXml,
    dataType: "xml",
    success: function(xml){
    console.log(xml);
    IWDatacapture.getItem(itemPath + "author_id_new").setValue($(xml).find("id").text());
    IWDatacapture.getItem(itemPath + "author_name_new").setValue($(xml).find("name").text());
    IWDatacapture.getItem(itemPath + "author_title_new").setValue($(xml).find("title").text());
    IWDatacapture.getItem(itemPath + "author_company_new").setValue($(xml).find("subtitle").text());
    IWDatacapture.getItem(itemPath + "author_image_new").setValue($(xml).find("photo").text());
    IWDatacapture.getItem(itemPath + "author_email_new").setValue($(xml).find("email").text());
    IWDatacapture.getItem(itemPath + "author_linkedin_new").setValue($(xml).find("linkedin").text());
    IWDatacapture.getItem(itemPath + "author_twitter_new").setValue($(xml).find("twitter").text());
    IWDatacapture.getItem(itemPath + "author_bio_new").setValue($(xml).find("bio").text());
      }
   });
}

// Call the initialization routine on load.
IWEventRegistry.addFormHandler("onFormInit", init);
IWEventRegistry.addFormHandler( "onSaveDone", handleOnSaveDone );
IWEventRegistry.addFormHandler( "onSave", handleOnSave );
IWEventRegistry.addItemHandler( "/press_release/author_dcr", "onItemChange", populateAuthor );
// Add event handler for each author
for (let i = 1; i <= 11; i++) { // Make sure this loops end value is the same as max number of authors in the root container
    IWEventRegistry.addItemHandler( "/press_release/author-section[" + i.toString() + "]/author/author_dcr_new", "onItemChange", populateAuthorNew );
}

